import { GuildMember, EmbedBuilder, TextChannel } from 'discord.js';
import { storage } from '../../storage';

export async function guildMemberAddHandler(member: GuildMember) {
  try {
    // Get server settings
    const server = await storage.getDiscordServer(member.guild.id);

    if (!server || !server.welcomeChannelId) {
      return; // No welcome channel configured
    }

    // Create or update Discord user
    let discordUser = await storage.getDiscordUser(member.id);
    if (!discordUser) {
      discordUser = await storage.createDiscordUser({
        id: member.id,
        username: member.user.username,
        discriminator: member.user.discriminator,
        avatar: member.user.avatar,
        isBot: member.user.bot,
      });
    }

    // Create server member record
    await storage.createServerMember({
      serverId: member.guild.id,
      userId: member.id,
    });

    // Send welcome message
    const channel = member.guild.channels.cache.get(server.welcomeChannelId) as TextChannel;

    if (channel) {
      const welcomeMessage = server.welcomeMessage || 
        `Welcome to the server, ${member}! We're excited to have you here!`;

      const embed = new EmbedBuilder()
        .setColor(0x5865f2)
        .setTitle('👋 Welcome to the Server!')
        .setDescription(welcomeMessage)
        .setThumbnail(member.user.displayAvatarURL())
        .addFields(
          { name: '📋 Server Rules', value: 'Check out the rules channel for guidelines', inline: true },
          { name: '💬 Get Started', value: 'Introduce yourself and start chatting!', inline: true },
          { name: '🎮 Have Fun', value: 'Join voice channels and participate in activities', inline: true }
        )
        .setFooter({ text: `Member #${member.guild.memberCount}` })
        .setTimestamp();

      await channel.send({ 
        content: `Welcome ${member}!`,
        embeds: [embed] 
      });
    }

    // Update server member count
    await storage.updateDiscordServer(member.guild.id, {
      memberCount: member.guild.memberCount,
    });

    console.log(`New member joined ${member.guild.name}: ${member.user.tag}`);
  } catch (error) {
    console.error('Error handling guild member add:', error);
  }
}

server/bot/events/interactionCreate.ts.content:
import { Interaction, ChatInputCommandInteraction } from 'discord.js';

export async function interactionCreateHandler(interaction: Interaction) {
  if (!interaction.isChatInputCommand()) return;

  const command = (interaction.client as any).commands.get(interaction.commandName);

  if (!command) {
    console.error(`No command matching ${interaction.commandName} was found.`);
    return;
  }

  try {
    await command.execute(interaction as ChatInputCommandInteraction);
  } catch (error) {
    console.error('Error executing command:', error);

    const errorMessage = { 
      content: 'There was an error while executing this command!', 
      ephemeral: true 
    };

    if (interaction.replied || interaction.deferred) {
      await interaction.followUp(errorMessage);
    } else {
      await interaction.reply(errorMessage);
    }
  }
}

server/bot/events/ready.ts.content:
import { Client, Events } from 'discord.js';
import { storage } from '../../storage';

export async function readyHandler(client: Client) {
  console.log(`Ready! Logged in as ${client.user?.tag}`);

  // Register slash commands globally
  try {
    const commands = (client as any).commands;
    const commandData = Array.from(commands.values()).map((command: any) => command.data.toJSON());

    await client.application?.commands.set(commandData);
    console.log(`Successfully registered ${commandData.length} slash commands.`);
  } catch (error) {
    console.error('Error registering slash commands:', error);
  }

  // Set bot activity
  client.user?.setActivity('Discord servers', { type: 3 }); // Type 3 = Watching

  // Initialize servers in database
  for (const guild of client.guilds.cache.values()) {
    try {
      const existingServer = await storage.getDiscordServer(guild.id);

      if (!existingServer) {
        await storage.createDiscordServer({
          id: guild.id,
          name: guild.name,
          ownerId: guild.ownerId,
          memberCount: guild.memberCount,
          isActive: true,
        });
        console.log(`Initialized server: ${guild.name}`);
      } else {
        // Update member count
        await storage.updateDiscordServer(guild.id, {
          memberCount: guild.memberCount,
          name: guild.name,
        });
      }
    } catch (error) {
      console.error(`Error initializing server ${guild.name}:`, error);
    }
  }
}

